// Filtrar conversas inativas há 24 horas (1440 minutos)
const data = $input.first().json;
const conversations = data.data?.payload || [];
const HORAS_INATIVIDADE = 24;
const LIMITE_MS = HORAS_INATIVIDADE * 60 * 60 * 1000;
const agora = Date.now();

const paraFollowUp = conversations.filter(conv => {
  // Ignorar conversas com agente atribuído (humano)
  if (conv.meta?.assignee) return false;
  // Ignorar conversas de bot do sistema
  if (conv.inbox_id === 7) return false;

  const lastActivity = conv.last_activity_at * 1000; // Unix timestamp → ms
  const tempoInativo = agora - lastActivity;
  return tempoInativo >= LIMITE_MS;
});

if (paraFollowUp.length === 0) return [];

return paraFollowUp.map(conv => ({
  json: {
    conversationId: conv.id,
    contactName: conv.meta?.sender?.name || 'Cliente',
    contactPhone: conv.meta?.sender?.phone_number || '',
    inboxId: conv.inbox_id,
    minutosInativo: Math.floor((agora - conv.last_activity_at * 1000) / 60000)
  }
}));

// Montar mensagem de follow-up com IA (GROK)
const d = $input.first().json;

const grokPayload = {
  model: 'x-ai/grok-2-latest',
  messages: [
    {
      role: 'system',
      content: `Você é a assistente virtual da Medeiros Assessoria Jurídica.
Crie uma mensagem curta e amigável de follow-up para um cliente que não respondeu há ${d.minutosInativo} minutos.
Seja cordial, demonstre interesse em ajudar e pergunte se ainda precisa de assistência.
Nome do cliente: ${d.contactName}.
Máximo 3 linhas. Use emojis com moderação.`
    },
    {
      role: 'user',
      content: 'Gere a mensagem de follow-up agora.'
    }
  ],
  max_tokens: 200,
  temperature: 0.8
};

return [{
  json: {
    ...d,
    grokPayload
  }
}];

// Extrair texto gerado pelo GROK
const grokResp = $input.first().json;
const conv = $('Filtrar Inativos 24h').item.json;

const mensagem = grokResp.choices?.[0]?.message?.content || 
  `Olá, ${conv.contactName}! 😊 Ainda podemos ajudá-lo(a)? Nossa equipe está disponível para esclarecer dúvidas e agendar sua consulta jurídica.`;

return [{
  json: {
    ...conv,
    mensagemFollowUp: mensagem.trim()
  }
}];
